ND_UNDERLYNG_COMPOSITION.N_FUND_INV_CAPITAL_INSTR_FI)) END ) ELSE NULL END,DIM_PARENT_EXPOSURE.N_ACCT_SKEY,RUN_PARAMETERS.N_RUN_PARAMETER_SETUP_SKEY,'870',1,FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE,'STG_FUND_UNDERLYNG_COMPOSITION','IFUC','CIU',to_char(FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY),to_char(FSI_CAP_INVESTMENT_EXPOSURES.N_COUNTRY_SKEY),to_char(FSI_CAP_INVESTMENT_EXPOSURES.N_ENTITY_SKEY),to_char(FSI_CAP_INVESTMENT_EXPOSURES.N_EXCHANGE_RATE),FSI_CAP_INVESTMENT_EXPOSURES.V_CCY_CODE,to_char(FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY),FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE,to_char(FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY),to_char(FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY) FROM STG_FUND_UNDERLYNG_COMPOSITION INNER JOIN DIM_EXPOSURE ON STG_FUND_UNDERLYNG_COMPOSITION.FIC_MIS_DATE = DIM_EXPOSURE.FIC_MIS_DATE AND SUBSTR(DIM_EXPOSURE.V_EXPOSURE_ID, 1, INSTR(DIM_EXPOSURE.V_EXPOSURE_ID, '_', - 1) - 1) = STG_FUND_UNDERLYNG_COMPOSITION.V_FUND_CODE || '_' || STG_FUND_UNDERLYNG_COMPOSITION.V_PROD_CODE INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = '870' INNER JOIN DIM_DATES ON DIM_DATES.D_CALENDAR_DATE = to_date('20260331','YYYYMMDD') INNER JOIN DIM_INSTRUMENT_CONTRACT ON DIM_INSTRUMENT_CONTRACT.V_INSTRUMENT_CODE = STG_FUND_UNDERLYNG_COMPOSITION.V_FUND_CODE AND DIM_INSTRUMENT_CONTRACT.FIC_MIS_DATE BETWEEN DIM_INSTRUMENT_CONTRACT.D_RECORD_START_DATE AND DIM_INSTRUMENT_CONTRACT.D_RECORD_END_DATE INNER JOIN FSI_CAP_INVESTMENT_EXPOSURES ON FSI_CAP_INVESTMENT_EXPOSURES.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_CAP_INVESTMENT_EXPOSURES.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_CAP_INVESTMENT_EXPOSURES.N_INSTRUMENT_SKEY = DIM_INSTRUMENT_CONTRACT.N_INSTRUMENT_SKEY INNER JOIN DIM_GAAP ON DIM_GAAP.N_GAAP_SKEY = FSI_CAP_INVESTMENT_EXPOSURES.N_GAAP_SKEY LEFT OUTER JOIN DIM_PRODUCT ON STG_FUND_UNDERLYNG_COMPOSITION.V_PROD_CODE = DIM_PRODUCT.V_PROD_CODE AND DIM_PRODUCT.FIC_MIS_DATE BETWEEN DIM_PRODUCT.D_RECORD_START_DATE AND DIM_PRODUCT.D_RECORD_END_DATE LEFT OUTER JOIN FSI_REG_PROD_TYPE_RECLASS ON FSI_REG_PROD_TYPE_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_REG_PROD_TYPE_RECLASS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_REG_PROD_TYPE_RECLASS.N_PROD_SKEY = DIM_PRODUCT.N_PROD_SKEY LEFT OUTER JOIN DIM_BASEL_PRODUCT_TYPE ON DIM_BASEL_PRODUCT_TYPE.N_BASEL_PROD_TYPE_SKEY = FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY AND DIM_BASEL_PRODUCT_TYPE.V_BASEL_PROD_TYPE_CODE_LEVEL1 <> 'OTD' LEFT OUTER JOIN DIM_PARTY_TYPE ON DIM_PARTY_TYPE.V_PARTY_TYPE_CODE = STG_FUND_UNDERLYNG_COMPOSITION.V_INSTR_ISSUER_TYPE_CODE AND DIM_PARTY_TYPE.FIC_MIS_DATE BETWEEN DIM_PARTY_TYPE.D_RECORD_START_DATE AND DIM_PARTY_TYPE.D_RECORD_END_DATE LEFT OUTER JOIN FSI_PARTY_TYPE_CLASSIFICATION ON FSI_PARTY_TYPE_CLASSIFICATION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_PARTY_TYPE_CLASSIFICATION.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_PARTY_TYPE_CLASSIFICATION.N_PARTY_TYPE_SKEY = DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY LEFT OUTER JOIN FCT_INSTRUMENT_CONTRACT_DTL ON FCT_INSTRUMENT_CONTRACT_DTL.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FCT_INSTRUMENT_CONTRACT_DTL.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FCT_INSTRUMENT_CONTRACT_DTL.N_INSTRUMENT_SKEY = DIM_INSTRUMENT_CONTRACT.N_INSTRUMENT_SKEY LEFT OUTER JOIN DIM_EXPOSURE DIM_PARENT_EXPOSURE ON STG_FUND_UNDERLYNG_COMPOSITION.V_FUND_CODE = DIM_PARENT_EXPOSURE.V_EXPOSURE_ID AND DIM_PARENT_EXPOSURE.FIC_MIS_DATE BETWEEN DIM_PARENT_EXPOSURE.D_RECORD_START_DATE AND DIM_PARENT_EXPOSURE.D_RECORD_END_DATE LEFT OUTER JOIN FSI_CAP_RUN_EXE_PARAMETERS ON DIM_RUN.N_RUN_SKEY = FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY AND DIM_DATES.n_date_skey = FSI_CAP_RUN_EXE_PARAMETERS.N_MIS_DATE_SKEY LEFT OUTER JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'NONSEC' LEFT OUTER JOIN RUN_PARAMETERS ON RUN_PARAMETERS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND RUN_PARAMETERS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = RUN_PARAMETERS.N_RUN_PARAMETER_SKEY LEFT OUTER JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE = FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE LEFT OUTER JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'INV_NON_SEC_ULY' INNER JOIN DIM_PARTY ON DIM_PARTY.N_PARTY_SKEY = COALESCE(FSI_CAP_INVESTMENT_EXPOSURES.N_CUST_SKEY, FSI_CAP_INVESTMENT_EXPOSURES.N_ISSUER_SKEY) WHERE 1=1 LOG ERRORS INTO FSI_CAP_INVESTMENT_EXPOSURES$ ('1776768452752_61955319_20260331_1_Job_7c33210edb224731af03715e1474c6ff') REJECT LIMIT 0;

